// Generated by OrchestKit Claude Plugin
// Tests for activation-channel skill telemetry (subagent channel + writer + schema)

import { describe, test, expect, beforeEach, afterEach } from 'vitest';
import { mkdtempSync, writeFileSync, readFileSync, rmSync, existsSync } from 'node:fs';
import { join } from 'node:path';
import { tmpdir } from 'node:os';
import { skillsInLine, skillChannelTracker } from '../../subagent-stop/skill-channel-tracker.js';
import { recordSkillChannel, SKILL_CHANNELS_FILE } from '../../lib/skill-channels.js';
import { flush } from '../../lib/analytics-buffer.js';
import { isValidSkillChannelEntry } from '../../lib/telemetry-schemas.js';
import { NOOP_CTX } from '../../lib/context.js';
import type { HookInput } from '../../types.js';

function baseInput(over: Partial<HookInput> = {}): HookInput {
  return {
    hook_event_name: 'SubagentStop',
    session_id: 'sess-1',
    tool_input: {},
    ...over,
  } as HookInput;
}

describe('skillsInLine — transcript parsing (real nested format)', () => {
  test('extracts Skill tool_use from message.content[]', () => {
    const line = {
      message: { content: [{ type: 'tool_use', name: 'Skill', input: { skill: 'ork:cover' } }] },
    };
    expect(skillsInLine(line)).toEqual(['ork:cover']);
  });

  test('ignores non-Skill tool_use and text blocks', () => {
    const line = {
      message: {
        content: [
          { type: 'text', text: 'thinking' },
          { type: 'tool_use', name: 'Bash', input: { command: 'ls' } },
          { type: 'tool_use', name: 'Skill', input: { skill: 'ork:verify' } },
        ],
      },
    };
    expect(skillsInLine(line)).toEqual(['ork:verify']);
  });

  test('returns [] for missing/empty/malformed content', () => {
    expect(skillsInLine({})).toEqual([]);
    expect(skillsInLine({ message: {} })).toEqual([]);
    expect(skillsInLine({ message: { content: 'string' } })).toEqual([]);
    expect(skillsInLine({ message: { content: [{ type: 'tool_use', name: 'Skill', input: {} }] } })).toEqual([]);
  });
});

describe('recordSkillChannel — writer + schema round-trip', () => {
  let tmp: string;
  beforeEach(() => { tmp = mkdtempSync(join(tmpdir(), 'chan-')); });
  afterEach(() => { rmSync(tmp, { recursive: true, force: true }); });

  test('writes a schema-valid row', () => {
    recordSkillChannel(tmp, { skill: 'ork:cover', channel: 'subagent', parent: 'test-generator', sessionId: 's1' });
    flush();
    const file = join(tmp, SKILL_CHANNELS_FILE);
    expect(existsSync(file)).toBe(true);
    const row = JSON.parse(readFileSync(file, 'utf8').trim().split('\n')[0]);
    expect(isValidSkillChannelEntry(row)).toBe(true);
    expect(row).toMatchObject({ skill: 'ork:cover', channel: 'subagent', parent: 'test-generator', session_id: 's1' });
    expect(typeof row.ts).toBe('string');
  });

  test('no-ops on empty skill name', () => {
    recordSkillChannel(tmp, { skill: '', channel: 'main' });
    flush();
    expect(existsSync(join(tmp, SKILL_CHANNELS_FILE))).toBe(false);
  });
});

describe('isValidSkillChannelEntry — schema lock', () => {
  test('accepts a canonical entry', () => {
    expect(isValidSkillChannelEntry({ ts: '2026-06-01T00:00:00.000Z', skill: 'ork:cover', channel: 'subagent', parent: 'x' })).toBe(true);
  });
  test('rejects bad channel / missing fields / bad ts', () => {
    expect(isValidSkillChannelEntry({ ts: '2026-06-01T00:00:00.000Z', skill: 'x', channel: 'bogus' })).toBe(false);
    expect(isValidSkillChannelEntry({ ts: '2026-06-01T00:00:00.000Z', channel: 'main' })).toBe(false);
    expect(isValidSkillChannelEntry({ ts: 'not-a-date', skill: 'x', channel: 'main' })).toBe(false);
    expect(isValidSkillChannelEntry(null)).toBe(false);
  });
});

describe('skillChannelTracker — handler', () => {
  let tmp: string;
  beforeEach(() => { tmp = mkdtempSync(join(tmpdir(), 'chan-h-')); });
  afterEach(() => { rmSync(tmp, { recursive: true, force: true }); });

  test('silent success when no transcript path', () => {
    const r = skillChannelTracker(baseInput(), NOOP_CTX);
    expect(r.continue).not.toBe(false);
  });

  test('silent success when transcript path missing on disk', () => {
    const r = skillChannelTracker(baseInput({ agent_transcript_path: join(tmp, 'nope.jsonl') }), NOOP_CTX);
    expect(r.continue).not.toBe(false);
  });

  test('records subagent-channel rows from a real-shaped transcript', () => {
    const transcript = join(tmp, 'agent.jsonl');
    writeFileSync(transcript, [
      JSON.stringify({ type: 'assistant', message: { content: [{ type: 'tool_use', name: 'Skill', input: { skill: 'ork:cover' } }] } }),
      JSON.stringify({ type: 'assistant', message: { content: [{ type: 'text', text: 'hi' }] } }),
      JSON.stringify({ type: 'assistant', message: { content: [{ type: 'tool_use', name: 'Skill', input: { skill: 'ork:verify' } }] } }),
    ].join('\n'), 'utf8');

    const r = skillChannelTracker(baseInput({
      project_dir: tmp,
      agent_transcript_path: transcript,
      subagent_type: 'test-generator',
    }), NOOP_CTX);
    expect(r.continue).not.toBe(false);
    flush();

    const file = join(tmp, SKILL_CHANNELS_FILE);
    expect(existsSync(file)).toBe(true);
    const rows = readFileSync(file, 'utf8').trim().split('\n').map((l) => JSON.parse(l));
    expect(rows).toHaveLength(2);
    expect(rows.every((r2) => isValidSkillChannelEntry(r2))).toBe(true);
    expect(rows.map((r2) => r2.skill)).toEqual(['ork:cover', 'ork:verify']);
    expect(rows.every((r2) => r2.channel === 'subagent' && r2.parent === 'test-generator')).toBe(true);
  });
});
